async function execute(api: TaskFlowScriptAPI, params: FlowParams): Promise<TaskFlowScriptResult> {
    const events = await api.callAction("calendar", "findTodaysEvents", {});

    if (!events.text || events.error) {
        return { success: false, error: events.error || "No events found" };
    }

    const formatted = await api.queryLLM(
        "Format these calendar events as a clean daily agenda with times and titles. Use bullet points.",
        { input: events.text, model: "claude-haiku-4-5-20251001" },
    );

    const result = await api.callAction("email", "sendEmail", {
        subject: "Daily Agenda",
        body: formatted.text,
        to: ["me"],
        genContent: { generateBody: false },
    });

    return { success: true, message: result.text };
}
